class AuthenticationInterceptor(grpc.ServerInterceptor):
    """
    Server interceptor that enforces authentication on all RPCs.
    Validates API keys/tokens from request metadata.
    """

    def __init__(self, valid_api_keys: set, exempt_methods: set = None):
        self._valid_api_keys = valid_api_keys
        self._exempt_methods = exempt_methods or {"/datastream.DataStreamService/HealthCheck"}
        self._auth_failure_count = 0
        self._lock = threading.Lock()

    def intercept_service(self, continuation, handler_call_details):
        method = handler_call_details.method

        # Allow health checks without auth
        if method in self._exempt_methods:
            return continuation(handler_call_details)

        # Extract metadata
        metadata = dict(handler_call_details.invocation_metadata or [])

        # Check for API key
        api_key = metadata.get("x-api-key", "")

        if not api_key:
            with self._lock:
                self._auth_failure_count += 1
            logging.warning(
                "Authentication failed: missing API key for method %s (total failures: %d)",
                method, self._auth_failure_count
            )
            return self._create_abort_handler(
                grpc.StatusCode.UNAUTHENTICATED,
                "Missing API key. Provide 'x-api-key' in metadata."
            )

        if api_key not in self._valid_api_keys:
            with self._lock:
                self._auth_failure_count += 1
            logging.warning(
                "Authentication failed: invalid API key for method %s (total failures: %d)",
                method, self._auth_failure_count
            )
            return self._create_abort_handler(
                grpc.StatusCode.UNAUTHENTICATED,
                "Invalid API key."
            )

        return continuation(handler_call_details)

    def _create_abort_handler(self, code, details):
        def _abort(request, context):
            context.abort(code, details)

        return grpc.unary_unary_rpc_method_handler(_abort)


class InputValidationInterceptor(grpc.ServerInterceptor):
    """
    Interceptor that validates and sanitizes incoming requests.
    Enforces maximum message sizes and payload constraints.
    """

    MAX_PAYLOAD_SIZE = 10 * 1024 * 1024  # 10 MB max payload
