class ServerMetrics:
    """Thread-safe server metrics collection."""

    def __init__(self):
        self._lock = threading.Lock()
        self._requests_processed = 0
        self._errors = 0
        self._total_processing_time_ns = 0
        self._start_time = time.time()
        self._active_streams = 0
        self._messages_received = 0
        self._messages_sent = 0

    def record_request(self, processing_time_ns: int, success: bool):
        with self._lock:
            self._requests_processed += 1
            self._total_processing_time_ns += processing_time_ns
            if not success:
                self._errors += 1

    def record_stream_message_received(self):
        with self._lock:
            self._messages_received += 1

    def record_stream_message_sent(self):
        with self._lock:
            self._messages_sent += 1

    def increment_active_streams(self):
        with self._lock:
            self._active_streams += 1

    def decrement_active_streams(self):
        with self._lock:
            self._active_streams -= 1

    @property
    def requests_processed(self) -> int:
        with self._lock:
            return self._requests_processed

    @property
    def uptime_seconds(self) -> int:
        return int(time.time() - self._start_time)

    def get_stats(self) -> dict:
        with self._lock:
            avg_time = (
                self._total_processing_time_ns / self._requests_processed
                if self._requests_processed > 0
                else 0
            )
            return {
                "requests_processed": self._requests_processed,
                "errors": self._errors,
                "avg_processing_time_ns": avg_time,
                "uptime_seconds": self.uptime_seconds,
                "active_streams": self._active_streams,
                "messages_received": self._messages_received,
                "messages_sent": self._messages_sent,
            }


