class DataStreamServiceServicer(datastream_pb2_grpc.DataStreamServiceServicer):
    """
    Implementation of the DataStreamService with security controls,
    input validation, and proper error handling.
    """

    # Maximum number of messages in a single streaming session
    MAX_STREAM_MESSAGES = 100000
    # Maximum duration for a streaming session (seconds)
    MAX_STREAM_DURATION = 3600  # 1 hour

    def __init__(self, metrics: ServerMetrics):
        self._processor = DataProcessor()
        self._metrics = metrics
        self._logger = logging.getLogger(__name__)

    def ProcessData(self, request, context):
        """Unary RPC: Process a single data request."""
        start_time = time.time_ns()
        success = False

        try:
            # Validate input
            is_valid, error_msg = self._processor.validate_request(request)
            if not is_valid:
                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                context.set_details(error_msg)
                return datastream_pb2.DataResponse(
                    request_id=request.request_id,
                    success=False,
                    error_message=error_msg,
                    processing_time_ns=time.time_ns() - start_time,
                )

            # Process the data
            result = self._processor.process(request.payload, dict(request.metadata))
            success = True

            processing_time = time.time_ns() - start_time
            return datastream_pb2.DataResponse(
                request_id=request.request_id,
                result=result,
                success=True,
                processing_time_ns=processing_time,
            )

        except Exception as e:
            self._logger.error("Error processing request %s: %s", request.request_id, str(e))
            processing_time = time.time_ns() - start_time
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details("Internal processing error")
            return datastream_pb2.DataResponse(
                request_id=request.request_id,
                success=False,
                error_message="Internal processing error",
                processing_time_ns=processing_time,
            )
        finally:
            self._metrics.record_request(time.time_ns() - start_time, success)

    def StreamData(self, request, context):
        """Server streaming RPC: Stream processed data back to client."""
        self._metrics.increment_active_streams()
        start_time = time.time()
        messages_sent = 0

        try:
            # Validate the initial request
            is_valid, error_msg = self._processor.validate_request(request)
            if not is_valid:
                context.set_code(grpc.StatusCode.INVALID_ARGUMENT)
                context.set_details(error_msg)
                return

            self._logger.info("Starting server stream for request %s", request.request_id)

            # Process and stream results
            # In a real system, this might read from a queue, database, or another stream
            chunk_size = 1024
            payload = request.payload
            offset = 0

            while offset < len(payload) and context.is_active():
                # Check stream duration limit
                if time.time() - start_time > self.MAX_STREAM_DURATION:
                    self._logger.warning(
                        "Stream duration limit reached for request %s", request.request_id
                    )
                    break

                # Check message count limit
                if messages_sent >= self.MAX_STREAM_MESSAGES:
                    self._logger.warning(
                        "Stream message limit reached for request %s", request.request_id
                    )
                    break

                chunk = payload[offset:offset + chunk_size]
                result = self._processor.process(chunk)

                response = datastream_pb2.DataResponse(
                    request_id=f"{request.request_id}-{messages_sent}",
                    result=result,
                    success=True,
                    processing_time_ns=time.time_ns(),
                    metadata={"chunk_index": str(messages_sent)},
                )

                yield response
                messages_sent += 1
                self._metrics.record_stream_message_sent()
                offset += chunk_size

            # If payload was empty, send at least one response
            if messages_sent == 0:
                result = self._processor.process(payload)
                yield datastream_pb2.DataResponse(
                    request_id=request.request_id,
                    result=result,
                    success=True,
                    processing_time_ns=time.time_ns() - int(start_time * 1e9),
                )
                messages_sent += 1
                self._metrics.record_stream_message_sent()

        except Exception as e:
            self._logger.error("Error in server stream for %s: %s", request.request_id, str(e))
            context.set_code(grpc.StatusCode.INTERNAL)
            context.set_details("Internal streaming error")
        finally:
            self._metrics.decrement_active_streams()
            self._logger.info(
                "Server stream ended for request %s: %d messages sent",
                request.request_id, messages_sent
            )

    def IngestStream(self, request_iterator, context):
        """Client streaming RPC: Ingest a stream of data from client."""
        self._metrics.increment_active_streams()
        start_time = time.time()
        messages_received = 0
        total_bytes = 0
        all_results = []
        last_request_id = ""

        try:
            for request in request_iterator:
                if not context.is_active():
                    break

                # Check stream duration limit
                if time.time() - start_time > self.MAX_STREAM_DURATION:
                    self._logger.warning("Ingest stream duration limit reached")
                    context.set_code(grpc.StatusCode.DEADLINE_EXCEEDED)
                    context.set_details("Stream duration limit exceeded")
                    break

                # Check message count limit
                if messages_received >= self.MAX_STREAM_MESSAGES:
                    self._logger.warning("Ingest stream message limit reached")
                    break

                # Validate each message
                is_valid, error_msg = self._processor.validate_request(request)
                if not is_valid:
                    self._logger.warning(
                        "Invalid message in stream: %s", error_msg
                    )
                    # Skip invalid messages but continue processing
                    messages_received += 1
                    continue

                # Check cumulative payload size (prevent memory exhaustion)
                total_bytes += len(request.payload)
                if total_bytes > 100 * 1024 * 1024:  # 100 MB cumulative limit
                    self._logger.warning("Cumulative payload size limit exceeded in ingest stream")
                    context.set_code(grpc.StatusCode.RESOURCE_EXHAUSTED)
                    context.set_details("Cumulative payload size limit exceeded")
                    break

                result = self._processor.process(request.payload, dict(request.metadata))
                all_results.append(result)
                last_request_id = request.request_id
                messages_received += 1
                self._metrics.record_stream_message_received()

            processing_time = time.time_ns() - int(start_time * 1e9)

            # Combine results
            combined_result = b"".join(all_results)

            return datastream_pb2.DataResponse(
                request_id=last_request_id,
                result=combined_result,
                success=True,
                processing_time_ns=processing_time,
                metadata={
                    "messages_received": str(messages_received),
                    "total_bytes_processed": str(total_bytes),
                },
            )

        except Exception as e:
            self._logger.error("Error in ingest stream: %s", str(e))
            return datastream_pb2.DataResponse(
                request_id=last_request_id,
                success=False,
                error_message="Internal streaming error",
                processing_time_ns=time.time_ns() - int(start_time * 1e9),
            )
        finally:
            self._metrics.decrement_active_streams()
            self._logger.info(
                "Ingest stream ended: %d messages received, %d bytes",
                messages_received, total_bytes
            )

    def BidirectionalStream(self, request_iterator, context):
        """Bidirectional streaming RPC: Process data in both directions."""
        self._metrics.increment_active_streams()
        start_time = time.time()
        messages_received = 0
        messages_sent = 0
        total_bytes_received = 0

        try:
            for request in request_iterator:
                if not context.is_active():
                    break

                # Check stream duration limit
                if time.time() - start_time > self.MAX_STREAM_DURATION:
                    self._logger.warning("Bidirectional stream duration limit reached")
                    break

                # Check message count limits
                if messages_received >= self.MAX_STREAM_MESSAGES:
                    self._logger.warning("Bidirectional stream message limit reached")
                    break

                # Validate
                is_valid, error_msg = self._processor.validate_request(request)
                if not is_valid:
                    yield datastream_pb2.DataResponse(
                        request_id=request.request_id,
                        success=False,
                        error_message=error_msg,
                        processing_time_ns=0,
                    )
                    messages_received += 1
                    messages_sent += 1
                    continue

                # Check cumulative size
                total_bytes_received += len(request.payload)
                if total_bytes_received > 100 * 1024 * 1024:  # 100 MB
                    yield datastream_pb2.DataResponse(
                        request_id=request.request_id,
                        success=False,
                        error_message="Cumulative payload size limit exceeded",
                    )
                    break

                messages_received += 1
                self._metrics.record_stream_message_received()

                # Process and respond
                msg_start = time.time_ns()
                result = self._processor.process(request.payload, dict(request.metadata))
                processing_time = time.time_ns() - msg_start

                response = datastream_pb2.DataResponse(
                    request_id=request.request_id,
                    result=result,
                    success=True,
                    processing_time_ns=processing_time,
                    metadata={"sequence": str(messages_sent)},
                )

                yield response
                messages_sent += 1
                self._metrics.record_stream_message_sent()

        except Exception as e:
            self._logger.error("Error in bidirectional stream: %s", str(e))
            yield datastream_pb2.DataResponse(
                request_id="error",
                success=False,
                error_message="Internal streaming error",
            )
        finally:
            self._metrics.decrement_active_streams()
            self._logger.info(
                "Bidirectional stream ended: %d received, %d sent, %d bytes",
                messages_received, messages_sent, total_bytes_received
            )

    def HealthCheck(self, request, context):
        """Health check endpoint."""
        stats = self._metrics.get_stats()
        return datastream_pb2.HealthResponse(
            status=datastream_pb2.HealthResponse.SERVING,
            uptime_seconds=stats["uptime_seconds"],
            requests_processed=stats["requests_processed"],
        )


