def load_tls_credentials(
    server_cert_path: str = None,
    server_key_path: str = None,
    ca_cert_path: str = None,
    require_client_cert: bool = False,
) -> grpc.ServerCredentials:
    """
    Load TLS credentials for secure communication.
    Supports mutual TLS (mTLS) when ca_cert_path is provided.
    """
    if not server_cert_path or not server_key_path:
        return None

    try:
        with open(server_key_path, "rb") as f:
            server_key = f.read()
        with open(server_cert_path, "rb") as f:
            server_cert = f.read()

        ca_cert = None
        if ca_cert_path:
            with open(ca_cert_path, "rb") as f:
                ca_cert = f.read()

        if require_client_cert and ca_cert:
            # Mutual TLS: require and verify client certificates
            credentials = grpc.ssl_server_credentials(
                [(server_key, server_cert)],
                root_certificates=ca_cert,
                require_client_auth=True,
            )
        else:
            credentials = grpc.ssl_server_credentials(
                [(server_key, server_cert)],
            )

        return credentials

    except FileNotFoundError as e:
        logging.error("TLS certificate file not found: %s", e)
        raise
    except Exception as e:
        logging.error("Failed to load TLS credentials: %s", e)
        raise


