def create_server(
    port: int = 50051,
    max_workers: int = 20,
    api_keys: set = None,
    tls_cert_path: str = None,
    tls_key_path: str = None,
    tls_ca_path: str = None,
    require_mtls: bool = False,
    max_requests_per_second: int = 1000,
    enable_reflection: bool = False,
) -> grpc.Server:
    """
    Create and configure the gRPC server with all security controls.
    """
    # Default API keys for development (MUST be changed in production)
    if api_keys is None:
        api_keys = {"dev-api-key-change-in-production"}
        logging.warning(
            "Using default API keys. Set proper API keys for production!"
        )

    # Create interceptors (order matters - they execute in order)
    interceptors = [
        AuditLoggingInterceptor(),
        AuthenticationInterceptor(valid_api_keys=api_keys),
        RateLimitInterceptor(max_requests_per_second=max_requests_per_second),
        InputValidationInterceptor(),
    ]

    # Server options for performance and security
    server_options = [
        # Performance tuning
        ("grpc.max_concurrent_streams", 1000),
        ("grpc.so_reuseport", 1),
        ("grpc.max_connection_idle_ms", 300000),  # 5 minutes
        ("grpc.max_connection_age_ms", 3600000),  # 1 hour - force reconnection
        ("grpc.max_connection_age_grace_ms", 30000),  # 30s grace period

        # Message size limits (enforce reasonable bounds)
        ("grpc.max_send_message_length", 16 * 1024 * 1024),  # 16 MB
        ("grpc.max_receive_message_length", 16 * 1024 * 1024),  # 16 MB

        # Keepalive settings
        ("grpc.keepalive_time_ms", 30000),  # 30 seconds
        ("grpc.keepalive_timeout_ms", 10000),  # 10 seconds
        ("grpc.keepalive_permit_without_calls", 0),  # Don't allow keepalive without active calls
        ("grpc.http2.max_pings_without_data", 2),
        ("grpc.http2.min_time_between_pings_ms", 30000),
        ("grpc.http2.min_ping_interval_without_data_ms", 30000),

        # Limit metadata size
        ("grpc.max_metadata_size", 8192),  # 8 KB max metadata
    ]

    # Create server with thread pool
    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=max_workers),
        interceptors=interceptors,
        options=server_options,
        maximum_concurrent_rpcs=5000,
    )

    # Create metrics and service
    metrics = ServerMetrics()
    servicer = DataStreamServiceServicer(metrics)

    # Register service
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)

    # Enable reflection only in development
    if enable_reflection:
        logging.warning("gRPC reflection is enabled. Disable in production!")
        SERVICE_NAMES = (
            datastream_pb2.DESCRIPTOR.services_by_name["DataStreamService"].full_name,
            reflection.SERVICE_NAME,
        )
        reflection.enable_server_reflection(SERVICE_NAMES, server)

    # Configure TLS
    tls_credentials = load_tls_credentials(
        server_cert_path=tls_cert_path,
        server_key_path=tls_key_path,
        ca_cert_path=tls_ca_path,
        require_client_cert=require_mtls,
    )

    if tls_credentials:
        server.add_secure_port(f"[::]:{port}", tls_credentials)
        logging.info("Server configured with TLS on port %d", port)
        if require_mtls:
            logging.info("Mutual TLS (mTLS) is enabled")
    else:
        # WARNING: Insecure port - only for development
        server.add_insecure_port(f"[::]:{port}")
        logging.warning(
            "Server running WITHOUT TLS on port %d. "
            "This is insecure and should only be used for development!",
            port,
        )

    return server, metrics


def serve():
    """Main server entry point."""
    # Configure logging
    logging.basicConfig(
        level=logging.INFO,
        format="%(asctime)s - %(name)s - %(levelname)s - %(message)s",
    )

    # Configure audit logger
    audit_logger = logging.getLogger("audit")
    audit_logger.setLevel(logging.INFO)

    # Server configuration from environment or defaults
    port = int(os.environ.get("GRPC_PORT", "50051"))
    max_workers = int(os.environ.get("GRPC_MAX_WORKERS", "20"))
    tls_cert = os.environ.get("GRPC_TLS_CERT")
    tls_key = os.environ.get("GRPC_TLS_KEY")
    tls_ca = os.environ.get("GRPC_TLS_CA")
    require_mtls = os.environ.get("GRPC_REQUIRE_MTLS", "false").lower() == "true"
    enable_reflection = os.environ.get("GRPC_ENABLE_REFLECTION", "false").lower() == "true"

    # API keys from environment (comma-separated)
    api_keys_str = os.environ.get("GRPC_API_KEYS", "dev-api-key-change-in-production")
    api_keys = set(k.strip() for k in api_keys_str.split(",") if k.strip())

    max_rps = int(os.environ.get("GRPC_MAX_RPS_PER_CLIENT", "1000"))

    server, metrics = create_server(
        port=port,
        max_workers=max_workers,
        api_keys=api_keys,
        tls_cert_path=tls_cert,
        tls_key_path=tls_key,
        tls_ca_path=tls_ca,
        require_mtls=require_mtls,
        max_requests_per_second=max_rps,
        enable_reflection=enable_reflection,
    )

    # Graceful shutdown handling
    shutdown_event = threading.Event()

    def handle_signal(signum, frame):
        logging.info("Received signal %d, initiating graceful shutdown...", signum)
        shutdown_event.set()

    signal.signal(signal.SIGINT, handle_signal)
    signal.signal(signal.SIGTERM, handle_signal)

    # Start server
    server.start()
    logging.info("gRPC server started on port %d with %d workers", port, max_workers)
    logging.info("Security: Authentication=%s, TLS=%s, mTLS=%s, RateLimit=%d/s",
                 "enabled", "enabled" if tls_cert else "disabled",
                 "enabled" if require_mtls else "disabled", max_rps)

    # Periodic stats logging
    def log_stats():
        while not shutdown_event.is_set():
            shutdown_event.wait(60)  # Log every 60 seconds
            if not shutdown_event.is_set():
                stats = metrics.get_stats()
                logging.info("Server stats: %s", stats)

    stats_thread = threading.Thread(target=log_stats, daemon=True)
    stats_thread.start()

    # Wait for shutdown signal
    shutdown_event.wait()

    # Graceful shutdown with timeout
    logging.info("Shutting down server (30s grace period)...")
    stopped_event = server.stop(30)
    stopped_event.wait()

    final_stats = metrics.get_stats()
    logging.info("Server stopped. Final stats: %s", final_stats)


if __name__ == "__main__":
    serve()